Швейцарский нож **кодирования/декодирования** для веб-пентеста: base64, URL, double-URL, HTML-entity, unicode (`\uXXXX`), charcode (`String.fromCharCode`), hex - в обе стороны (encode/decode). Пригождается каждый день: обойти фильтры, разобрать payload из трафика, собрать XSS/SQLi в нужной обёртке, расшифровать токен. Читает из аргумента или stdin (пайп), что удобно в связке с другими тулзами.

> Полностью офлайн, stdlib. Для двойного URL-кодирования применяй `double-url` (частый обход WAF). `unicode`/`charcode` удобны для JS-контекста XSS. Декодирование «угадайкой» тут не делается - указывай схему явно.

```python
#!/usr/bin/env python3
# enctool.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
# Multi-scheme encoder/decoder: base64,url,double-url,html,unicode,charcode,hex.
import argparse, base64, html, sys, urllib.parse

def enc(scheme, s):
    b = s.encode("utf-8", "surrogatepass")
    if scheme == "base64":   return base64.b64encode(b).decode()
    if scheme == "url":      return urllib.parse.quote(s, safe="")
    if scheme == "double-url": return urllib.parse.quote(urllib.parse.quote(s, safe=""), safe="")
    if scheme == "html":     return html.escape(s).replace("'", "&#x27;")
    if scheme == "unicode":  return "".join(f"\\u{ord(c):04x}" for c in s)
    if scheme == "charcode": return ",".join(str(ord(c)) for c in s)
    if scheme == "hex":      return b.hex()
    raise ValueError(scheme)

def dec(scheme, s):
    if scheme == "base64":   return base64.b64decode(s + "=" * (-len(s) % 4)).decode("utf-8", "replace")
    if scheme == "url":      return urllib.parse.unquote(s)
    if scheme == "double-url": return urllib.parse.unquote(urllib.parse.unquote(s))
    if scheme == "html":     return html.unescape(s)
    if scheme == "unicode":  return s.encode().decode("unicode_escape")
    if scheme == "charcode": return "".join(chr(int(x)) for x in s.replace(" ", "").split(",") if x)
    if scheme == "hex":      return bytes.fromhex(s.replace(" ", "").replace("0x", "")).decode("utf-8", "replace")
    raise ValueError(scheme)

SCHEMES = ["base64", "url", "double-url", "html", "unicode", "charcode", "hex"]

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL encoder/decoder")
    ap.add_argument("scheme", choices=SCHEMES)
    ap.add_argument("-d", "--decode", action="store_true", help="decode instead of encode")
    ap.add_argument("data", nargs="?", help="input (or read from stdin if omitted)")
    a = ap.parse_args()
    data = a.data if a.data is not None else sys.stdin.read().rstrip("\n")
    out = dec(a.scheme, data) if a.decode else enc(a.scheme, data)
    sys.stdout.write(out + "\n")

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 enctool.py base64 "<script>alert(1)</script>"
python3 enctool.py double-url "../../etc/passwd"
echo "PHNjcmlwdD4=" | python3 enctool.py base64 -d
python3 enctool.py unicode "<img src=x>"
```

Декодирует **JWT** без проверки подписи: разбивает на header/payload/signature, base64url-декодит (с догоном паддинга, которого в JWT нет) и красиво печатает JSON. Подсвечивает важные клеймы: `alg`, `kid`, `exp`/`iat`/`nbf` (с пересчётом в дату и пометкой «истёк»). Первый шаг анализа любого токена: понять алгоритм, claims и срок жизни перед попыткой подделки.

> JWT использует **base64url БЕЗ padding** - поэтому добиваем `=` вручную. Подпись не проверяется (её и нечем без ключа). `alg:none` или `alg:HS256` при наличии публичного RSA-ключа -> смотри `jwt_forge.py`.

```python
#!/usr/bin/env python3
# jwt_decode.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
# Decode a JWT (no signature verification) and highlight key claims.
import base64, datetime, json, sys

def b64url_decode(seg):
    seg += "=" * (-len(seg) % 4)            # JWT base64url has no padding
    return base64.urlsafe_b64decode(seg)

def show(name, seg):
    try:
        obj = json.loads(b64url_decode(seg))
    except Exception as e:
        print(f"[!] {name}: cannot decode ({e})"); return {}
    print(f"== {name} ==")
    print(json.dumps(obj, indent=2, ensure_ascii=False))
    return obj

def ts(label, v):
    try:
        d = datetime.datetime.utcfromtimestamp(int(v))
        flag = "  <-- EXPIRED" if label == "exp" and d < datetime.datetime.utcnow() else ""
        print(f"    {label} = {v}  ({d} UTC){flag}")
    except Exception:
        pass

def main():
    if len(sys.argv) < 2:
        token = sys.stdin.read().strip()
    else:
        token = sys.argv[1].strip()
    parts = token.split(".")
    if len(parts) < 2:
        sys.exit("[!] not a JWT (need at least header.payload)")
    hdr = show("HEADER", parts[0])
    pl = show("PAYLOAD", parts[1])
    print("== NOTES ==")
    print(f"    alg = {hdr.get('alg')!r}   kid = {hdr.get('kid')!r}")
    for c in ("iat", "nbf", "exp"):
        if c in pl:
            ts(c, pl[c])
    sig = parts[2] if len(parts) > 2 else ""
    print(f"    signature present: {bool(sig)} ({len(sig)} chars, NOT verified)")

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 jwt_decode.py "eyJhbGciOi...<token>"
echo "eyJ...<token>" | python3 jwt_decode.py
```

Проверяет **CORS-мисконфиг**: шлёт запрос с подставным `Origin: https://evil.example` и смотрит ответные заголовки `Access-Control-Allow-Origin` (ACAO) и `Access-Control-Allow-Credentials` (ACAC). Классифицирует находки: **HIGH** - сервер отражает любой Origin (`ACAO == твой evil`) И отдаёт `ACAC: true` (можно красть аутентифицированные данные жертвы); MEDIUM - `null`-origin reflection или доверие к произвольному поддомену; INFO - wildcard `*` без credentials. Тестирует несколько payload-origin (reflected, null, subdomain-suffix, pre-domain).

> Самый опасный кейс - именно **reflected-origin + credentials=true**: это полноценная кража данных. `ACAO: *` с `credentials` браузер запрещает, поэтому одиночный `*` без креденшелов - обычно лишь INFO. Скрипт не отправляет настоящих кук, он только читает политику.

```python
#!/usr/bin/env python3
# cors_check.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
# Detect permissive CORS: reflected origin + credentials = HIGH.
import argparse, ssl, sys, urllib.request

def probe(url, origin, timeout):
    ctx = ssl.create_default_context()
    ctx.check_hostname = False; ctx.verify_mode = ssl.CERT_NONE
    req = urllib.request.Request(url, headers={
        "Origin": origin, "User-Agent": "ARS3NAL-cors/1.0"})
    try:
        with urllib.request.urlopen(req, timeout=timeout, context=ctx) as r:
            h = r.headers
            return h.get("Access-Control-Allow-Origin"), h.get("Access-Control-Allow-Credentials")
    except urllib.error.HTTPError as e:
        return e.headers.get("Access-Control-Allow-Origin"), e.headers.get("Access-Control-Allow-Credentials")
    except Exception as e:
        return None, f"err:{e}"

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL CORS misconfig checker")
    ap.add_argument("url")
    ap.add_argument("-t", "--timeout", type=int, default=15)
    a = ap.parse_args()
    host = a.url.split("//", 1)[-1].split("/", 1)[0]
    tests = {
        "reflected":  "https://evil-ars3nal.example",
        "null":       "null",
        "subdomain":  f"https://evil-ars3nal.{host}",
        "suffix":     f"https://{host}.evil-ars3nal.example",
        "prefix":     f"https://evil-ars3nal-{host}",
    }
    worst = "none"
    for name, origin in tests.items():
        acao, acac = probe(a.url, origin, a.timeout)
        creds = str(acac).lower() == "true"
        sev = "INFO"
        if acao == origin and creds:
            sev = "HIGH"
        elif acao == origin or acao == "null":
            sev = "MEDIUM"
        elif acao == "*":
            sev = "INFO"
        else:
            sev = "ok"
        if sev in ("HIGH", "MEDIUM") and worst != "HIGH":
            worst = sev
        print(f"  [{sev:6}] Origin={origin:42}  ACAO={acao!r}  creds={acac!r}")
    print(f"[=] worst finding: {worst}")
    sys.exit(0)

if __name__ == "__main__":
    main()
```

Запуск:
```bash
python3 cors_check.py https://api.target.example.com/account
```
